use std::fmt::Display;

trait AreaCalculator {
    fn calculate_area(&self) -> f64;
}

struct Circle { 
    radius: f64,
}

impl AreaCalculator for Circle {
    fn calculate_area(&self) -> f64 {
        std::f64::consts::PI * self.radius * self.radius
    }
}

struct Rectangle { 
    width: f64,
    height: f64,
}

impl AreaCalculator for Rectangle {
    fn calculate_area(&self) -> f64 {
        self.width * self.height
    }
}

fn process_shapes(shapes: Vec<Box<dyn AreaCalculator>>) -> Vec<f64> {
    let mut areas = Vec::new();
    for shape in shapes {
        areas.push(shape.calculate_area());
    }
    areas
}

fn main() {
    let circle = Circle { radius: 5.0 };
    let rectangle = Rectangle { width: 4.0, height: 3.0 };

    let shapes: Vec<Box<dyn AreaCalculator>> = vec![Box::new(circle),
                                                    Box::new(rectangle)];

    let results = process_shapes(shapes);

    println!("Calculated areas: {}", results.len());
    for area in results {
        println!("Area: {:.2}", area);
    }
}

use std::fmt::{self, Display};

trait Processable {
    fn get_id(&self) -> u32;
    fn display_info(&self) -> String;
}

struct WidgetA {
    id: u32,
    name: String,
}

impl Processable for WidgetA {
    fn get_id(&self) -> u32 {
        self.id
    }
    fn display_info(&self) -> String {
        format!("Widget A ID: {}", self.id)
    }
}

struct DataB {
    key: u32,
    value: String,
}

impl Processable for DataB {
    fn get_id(&self) -> u32 {
        self.key
    }
    fn display_info(&self) -> String {
        format!("Data B Key: {}", self.key)
    }
}

fn process_items<T>(items: &[T]) -> Result<(), Box<dyn std::error::Error>>
where
    T: Processable + 'static,
{
    for item in items {
        println!("Processing {}", item.display_info());
        let _ = item.get_id();
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let widgets: Vec<Box<dyn Processable + 'static>> = vec![
        Box::new(WidgetA { id: 101, name: "First".to_string() }),
        Box::new(DataB { key: 202, value: "Second".to_string() }),
    ];

    // This demonstrates the need for trait objects when returning different concrete types.
    for widget in widgets.iter() {
        println!("--- Encountered Item ---");
        println!("ID check: {}", widget.get_id());
        println!("Info: {}", widget.display_info());
    }

    Ok(())
}

use std::fmt::Debug;

trait PositionCalculator {
    fn calculate_final_position(&self, start: (f64, f64), input: (f64, f64)) -> (f64, f64);
}

struct Circle { 
    radius: f64
}
impl PositionCalculator for Circle {
    fn calculate_final_position(&self, start: (f64, f64), input: (f64, f64)) -> (f64, f64) {
        (start.0 + self.radius * input.0, start.1 + self.radius * input.1)
    }
}

struct Rectangle { 
    width: f64,
    height: f64
}
impl PositionCalculator for Rectangle {
    fn calculate_final_position(&self, start: (f64, f64), input: (f64, f64)) -> (f64, f64) {
        (start.0 + self.width * input.0, start.1 + self.height * input.1)
    }
}

fn process_position<T: PositionCalculator>(calculator: &T, start: (f64, f64), input: (f64, f64)) -> (f64, f64) {
    calculator.calculate_final_position(start, input)
}

fn main() {
    let circle = Circle { radius: 5.0 };
    let rect = Rectangle { width: 10.0, height: 2.0 };
    let start_pos = (1.0, 1.0);
    let input_factor = (2.0, 3.0);

    let circle_result = process_position(&circle, start_pos, input_factor);
    println!("Circle Final Position: ({:.2}, {:.2})", circle_result.0, circle_result.1);

    let rect_result = process_position(&rect, start_pos, input_factor);
    println!("Rectangle Final Position: ({:.2}, {:.2})", rect_result.0, rect_result.1);
}

use std::error::Error;

trait Processor<T> {
    fn process(&self, item: T) -> Result<(), Box<dyn Error>>;
}

struct FileProcessor;

impl Processor<String> for FileProcessor {
    fn process(&self, item: String) -> Result<(), Box<dyn Error>> {
        println!("Processing file data: {}", item);
        Ok(())
    }
}

struct NetworkProcessor;

impl Processor<i32> for NetworkProcessor {
    fn process(&self, item: i32) -> Result<(), Box<dyn Error>> {
        println!("Processing network ID: {}", item);
        Ok(())
    }
}

fn run_processing<P>(processor: &P, data: String) -> Result<(), Box<dyn Error>> where P: Processor<String> + ?Sized {
    processor.process(data)
}

fn main() -> Result<(), Box<dyn Error>> {
    let file_handler = FileProcessor;
    run_processing(&file_handler, "Some secret data".to_string())?;

    let network_handler = NetworkProcessor;
    // This line would fail to compile if we tried to pass a String here because the trait bounds are specific.
    // We demonstrate usage with types that match the generic constraints defined in run_processing.
    Ok(()) 
}
